export function draw(ctx, w, h, opts = {}) {
	const { rotX = -0.35, rotY = 0.6, dist = 5, scale = 1, light = [0.5, 0.7, 0.6] } = opts;
	const cx = w / 2, cy = h / 2, f = Math.min(w, h) * 0.9 * scale;
	const cosX = Math.cos(rotX), sinX = Math.sin(rotX);
	const cosY = Math.cos(rotY), sinY = Math.sin(rotY);
	const ll = Math.hypot(light[0], light[1], light[2]) || 1;
	const L = [light[0] / ll, light[1] / ll, light[2] / ll];

	function rot(p) {
		let x = p[0] * cosY + p[2] * sinY;
		let z = -p[0] * sinY + p[2] * cosY;
		const y = p[1] * cosX - z * sinX;
		z = p[1] * sinX + z * cosX;
		return [x, y, z];
	}
	function shade(hex, k) {
		const n = parseInt(hex.slice(1), 16);
		return 'rgb(' + (((n >> 16) & 255) * k | 0) + ',' + (((n >> 8) & 255) * k | 0) + ',' + ((n & 255) * k | 0) + ')';
	}

	const faces = triangles.map((t) => {
		const r = t.p.map(rot);
		return { r, c: t.c, z: (r[0][2] + r[1][2] + r[2][2]) / 3 };
	});
	faces.sort((a, b) => a.z - b.z); // far first

	for (const fc of faces) {
		const r = fc.r;
		const ux = r[1][0] - r[0][0], uy = r[1][1] - r[0][1], uz = r[1][2] - r[0][2];
		const vx = r[2][0] - r[0][0], vy = r[2][1] - r[0][1], vz = r[2][2] - r[0][2];
		let nx = uy * vz - uz * vy, ny = uz * vx - ux * vz, nz = ux * vy - uy * vx;
		const nl = Math.hypot(nx, ny, nz) || 1;
		nx /= nl; ny /= nl; nz /= nl;
		if (nz <= 0) continue; // backface cull
		const lambert = Math.max(0, nx * L[0] + ny * L[1] + nz * L[2]);
		ctx.fillStyle = shade(fc.c, 0.35 + 0.65 * lambert);
		ctx.beginPath();
		for (let i = 0; i < 3; i++) {
			const pz = dist - r[i][2], s = f / pz;
			const sx = cx + r[i][0] * s, sy = cy - r[i][1] * s;
			if (i === 0) ctx.moveTo(sx, sy); else ctx.lineTo(sx, sy);
		}
		ctx.closePath();
		ctx.fill();
	}
}
